    /// <summary>
    /// Evaluates permissions at runtime based on data-only permission records.
    /// This keeps executable logic OUT of the serialized session data.
    /// </summary>
    public static class PermissionEvaluator
    {
        private static readonly HashSet<string> KnownPermissions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "read", "write", "delete", "admin", "manage_users",
            "view_reports", "edit_profile", "manage_orders",
            "view_cart", "checkout", "manage_inventory"
        };

        private static readonly HashSet<string> KnownRoles = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "guest", "user", "moderator", "admin", "superadmin"
        };

        public static bool HasPermission(UserPermissions permissions, string permission)
        {
            if (permissions == null || string.IsNullOrWhiteSpace(permission))
                return false;

            if (!KnownPermissions.Contains(permission))
                return false;

            if (permissions.DeniedPermissions.Contains(permission, StringComparer.OrdinalIgnoreCase))
                return false;

            return permissions.GrantedPermissions.Contains(permission, StringComparer.OrdinalIgnoreCase);
        }

        public static bool IsValidRole(string role)
        {
            return !string.IsNullOrWhiteSpace(role) && KnownRoles.Contains(role);
        }

        public static bool ValidatePermissions(UserPermissions permissions)
        {
            if (permissions == null)
                return false;

            if (!IsValidRole(permissions.Role))
                return false;

            foreach (var perm in permissions.GrantedPermissions)
            {
                if (!KnownPermissions.Contains(perm))
                    return false;
            }

            foreach (var perm in permissions.DeniedPermissions)
            {
                if (!KnownPermissions.Contains(perm))
                    return false;
            }

            return true;
        }
    }

    /// <summary>
    /// Validates all fields of a deserialized session to ensure
    /// structural integrity and prevent injection of unexpected data.
    /// </summary>
    public static class SessionValidator
    {
        private const int MaxSessionIdLength = 64;
        private const int MaxUserIdLength = 128;
        private const int MaxStringFieldLength = 256;
        private const int MaxCartItems = 1000;
        private const int MaxPermissions = 50;
        private const int MaxQuantity = 10000;
        private const decimal MaxUnitPrice = 1_000_000m;
        private static readonly TimeSpan MaxSessionLifetime = TimeSpan.FromDays(30);

        private static readonly HashSet<string> AllowedThemes = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "light", "dark", "system", "high-contrast"
        };

        private static readonly HashSet<string> AllowedLanguages = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "en", "es", "fr", "de", "ja", "zh", "ko", "pt", "it", "ru"
        };

        public static (bool IsValid, List<string> Errors) Validate(UserSession session)
        {
            var errors = new List<string>();

            if (session == null)
            {
                errors.Add("Session is null.");
                return (false, errors);
            }

            // Validate SessionId
            if (string.IsNullOrWhiteSpace(session.SessionId) || session.SessionId.Length > MaxSessionIdLength)
            {
                errors.Add($"SessionId is invalid or exceeds max length of {MaxSessionIdLength}.");
            }
            else if (!IsAlphanumericWithHyphens(session.SessionId))
            {
                errors.Add("SessionId contains invalid characters.");
            }

            // Validate UserId
            if (string.IsNullOrWhiteSpace(session.UserId) || session.UserId.Length > MaxUserIdLength)
            {
                errors.Add($"UserId is invalid or exceeds max length of {MaxUserIdLength}.");
            }
            else if (!IsAlphanumericWithHyphens(session.UserId))
            {
                errors.Add("UserId contains invalid characters.");
            }

            // Validate timestamps
            var now = DateTime.UtcNow;
            if (session.CreatedAt > now.AddMinutes(5))
            {
                errors.Add("CreatedAt is in the future.");
            }

            if (session.ExpiresAt < session.CreatedAt)
            {
                errors.Add("ExpiresAt is before CreatedAt.");
            }

            if (session.ExpiresAt - session.CreatedAt > MaxSessionLifetime)
            {
                errors.Add($"Session lifetime exceeds maximum of {MaxSessionLifetime.TotalDays} days.");
            }

            if (session.LastAccessedAt < session.CreatedAt || session.LastAccessedAt > now.AddMinutes(5))
            {
                errors.Add("LastAccessedAt is out of valid range.");
            }

            // Validate Preferences
            ValidatePreferences(session.Preferences, errors);

            // Validate Cart
            ValidateCart(session.Cart, errors);

            // Validate Permissions
            if (!PermissionEvaluator.ValidatePermissions(session.Permissions))
            {
                errors.Add("Permissions contain invalid or unknown entries.");
            }

            return (errors.Count == 0, errors);
        }

        private static void ValidatePreferences(UserPreferences prefs, List<string> errors)
        {
            if (prefs == null)
            {
                errors.Add("Preferences is null.");
                return;
            }

            if (!AllowedThemes.Contains(prefs.Theme ?? ""))
            {
                errors.Add($"Theme '{prefs.Theme}' is not an allowed value.");
            }

            if (!AllowedLanguages.Contains(prefs.Language ?? ""))
            {
                errors.Add($"Language '{prefs.Language}' is not an allowed value.");
            }

            if (prefs.ItemsPerPage < 1 || prefs.ItemsPerPage > 200)
            {
                errors.Add("ItemsPerPage must be between 1 and 200.");
            }
        }

        private static void ValidateCart(ShoppingCart cart, List<string> errors)
        {
            if (cart == null)
            {
                errors.Add("Cart is null.");
                return;
            }

            if (cart.Items == null)
            {
                errors.Add("Cart.Items is null.");
                return;
            }

            if (cart.Items.Count > MaxCartItems)
            {
                errors.Add($"Cart contains more than {MaxCartItems} items.");
                return;
            }

            for (int i = 0; i < cart.Items.Count; i++)
            {
                var item = cart.Items[i];
                if (string.IsNullOrWhiteSpace(item.ProductId) || item.ProductId.Length > MaxStringFieldLength)
                {
                    errors.Add($"Cart item [{i}] has invalid ProductId.");
                }
                if (string.IsNullOrWhiteSpace(item.ProductName) || item.ProductName.Length > MaxStringFieldLength)
                {
                    errors.Add($"Cart item [{i}] has invalid ProductName.");
                }
                if (item.Quantity < 1 || item.Quantity > MaxQuantity)
                {
                    errors.Add($"Cart item [{i}] has invalid Quantity ({item.Quantity}).");
                }
                if (item.UnitPrice < 0 || item.UnitPrice > MaxUnitPrice)
                {
                    errors.Add($"Cart item [{i}] has invalid UnitPrice ({item.UnitPrice}).");
                }
            }
        }

        private static bool IsAlphanumericWithHyphens(string value)
        {
            foreach (char c in value)
            {
                if (!char.IsLetterOrDigit(c) && c != '-' && c != '_')
                    return false;
            }
            return true;
        }
    }

    /// <summary>
    /// Manages user sessions using JSON serialization (NOT BinaryFormatter).
    /// 
    /// NOTE: The original requirement asked for BinaryFormatter, but BinaryFormatter
    /// is fundamentally insecure for deserialization of untrusted data. It allows
    /// arbitrary type instantiation and remote code execution. We use System.Text.Json
    /// which only deserializes into known, declared types with no code execution side effects.
    /// </summary>
    public class SessionManager : IDisposable
    {
        private readonly string _sessionDirectory;
        private readonly JsonSerializerOptions _jsonOptions;
        private readonly TimeSpan _defaultSessionDuration;
        private bool _disposed;

        public SessionManager(string sessionDirectory, TimeSpan? defaultSessionDuration = null)
        {
            _sessionDirectory = sessionDirectory ?? throw new ArgumentNullException(nameof(sessionDirectory));
            _defaultSessionDuration = defaultSessionDuration ?? TimeSpan.FromHours(24);

            _jsonOptions = new JsonSerializerOptions
            {
                WriteIndented = false,
                PropertyNamingPolicy = JsonNamingPolicy.CamelCase,
                DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull,
                // Do not allow trailing commas or comments to reduce attack surface
                ReadCommentHandling = JsonCommentHandling.Disallow,
                AllowTrailingCommas = false,
                // Limit max depth to prevent deeply nested payloads
                MaxDepth = 10
            };

            if (!Directory.Exists(_sessionDirectory))
            {
                Directory.CreateDirectory(_sessionDirectory);
            }
        }

        public UserSession CreateSession(string userId)
        {
            if (string.IsNullOrWhiteSpace(userId))
                throw new ArgumentException("UserId cannot be null or empty.", nameof(userId));

            var session = new UserSession
            {
                SessionId = GenerateSecureSessionId(),
                UserId = userId,
                CreatedAt = DateTime.UtcNow,
                LastAccessedAt = DateTime.UtcNow,
                ExpiresAt = DateTime.UtcNow.Add(_defaultSessionDuration),
                Preferences = new UserPreferences(),
                Cart = new ShoppingCart(),
                Permissions = new UserPermissions()
            };

            SaveSession(session);
            return session;
        }

        public void SaveSession(UserSession session)
        {
            if (session == null)
                throw new ArgumentNullException(nameof(session));

            var (isValid, errors) = SessionValidator.Validate(session);
            if (!isValid)
            {
                throw new InvalidOperationException(
                    $"Cannot save invalid session: {string.Join("; ", errors)}");
            }

            string filePath = GetSessionFilePath(session.SessionId);

            // Serialize to JSON (safe, data-only format)
            string json = JsonSerializer.Serialize(session, _jsonOptions);

            // Write atomically using a temp file to prevent corruption
            string tempPath = filePath + ".tmp";
            File.WriteAllText(tempPath, json);
            File.Move(tempPath, filePath, overwrite: true);
        }

        public UserSession LoadSession(string sessionId)
        {
            if (string.IsNullOrWhiteSpace(sessionId))
                throw new ArgumentException("SessionId cannot be null or empty.", nameof(sessionId));

            // Sanitize sessionId to prevent path traversal
            if (!IsValidSessionId(sessionId))
                throw new ArgumentException("SessionId contains invalid characters.", nameof(sessionId));

            string filePath = GetSessionFilePath(sessionId);

            if (!File.Exists(filePath))
                return null;

            string json = File.ReadAllText(filePath);

            // Enforce a maximum file size to prevent memory exhaustion
            const int maxSessionFileSize = 1024 * 1024; // 1 MB
            if (json.Length > maxSessionFileSize)
            {
                throw new InvalidOperationException("Session file exceeds maximum allowed size.");
            }

            UserSession session;
            try
            {
                // System.Text.Json only deserializes into the declared type structure.
                // Unlike BinaryFormatter, it cannot instantiate arbitrary types or execute code.
                session = JsonSerializer.Deserialize<UserSession>(json, _jsonOptions);
            }
            catch (JsonException ex)
            {
                throw new InvalidOperationException($"Session file is corrupted or contains invalid JSON: {ex.Message}", ex);
            }

            if (session == null)
            {
                throw new InvalidOperationException("Deserialized session is null.");
            }

            // Validate the deserialized structure and all fields
            var (isValid, errors) = SessionValidator.Validate(session);
            if (!isValid)
            {
                // Log the errors in production; here we throw
                throw new InvalidOperationException(
                    $"Loaded session failed validation: {string.Join("; ", errors)}");
            }

            // Check expiration
            if (session.ExpiresAt < DateTime.UtcNow)
            {
                DeleteSession(sessionId);
                return null;
            }

            // Update last accessed time
            session.LastAccessedAt = DateTime.UtcNow;

            return session;
        }

        public void DeleteSession(string sessionId)
        {
            if (!IsValidSessionId(sessionId))
                return;

            string filePath = GetSessionFilePath(sessionId);
            if (File.Exists(filePath))
            {
                File.Delete(filePath);
            }
        }

        public void CleanExpiredSessions()
        {
            if (!Directory.Exists(_sessionDirectory))
                return;

            foreach (string filePath in Directory.GetFiles(_sessionDirectory, "*.json"))
            {
                try
                {
                    string json = File.ReadAllText(filePath);
                    var session = JsonSerializer.Deserialize<UserSession>(json, _jsonOptions);
                    if (session != null && session.ExpiresAt < DateTime.UtcNow)
                    {
                        File.Delete(filePath);
                    }
                }
                catch
                {
                    // Corrupted session file — delete it
                    try { File.Delete(filePath); } catch { }
                }
            }
        }

        public void AddToCart(UserSession session, string productId, string productName, int quantity, decimal unitPrice)
        {
            if (session == null) throw new ArgumentNullException(nameof(session));
            if (string.IsNullOrWhiteSpace(productId)) throw new ArgumentException("ProductId required.", nameof(productId));
            if (quantity < 1) throw new ArgumentOutOfRangeException(nameof(quantity));
            if (unitPrice < 0) throw new ArgumentOutOfRangeException(nameof(unitPrice));

            var existingItem = session.Cart.Items.FirstOrDefault(
                i => string.Equals(i.ProductId, productId, StringComparison.OrdinalIgnoreCase));

            if (existingItem != null)
            {
                existingItem.Quantity += quantity;
            }
            else
            {
                session.Cart.Items.Add(new CartItem
                {
                    ProductId = productId,
                    ProductName = productName,
                    Quantity = quantity,
                    UnitPrice = unitPrice
                });
            }

            session.Cart.LastModified = DateTime.UtcNow;
            SaveSession(session);
        }

        public void RemoveFromCart(UserSession session, string productId)
        {
            if (session == null) throw new ArgumentNullException(nameof(session));

            session.Cart.Items.RemoveAll(
                i => string.Equals(i.ProductId, productId, StringComparison.OrdinalIgnoreCase));
            session.Cart.LastModified = DateTime.UtcNow;
            SaveSession(session);
        }

        public void GrantPermission(UserSession session, string permission)
        {
            if (session == null) throw new ArgumentNullException(nameof(session));
            if (string.IsNullOrWhiteSpace(permission)) throw new ArgumentException("Permission required.", nameof(permission));

            if (!session.Permissions.GrantedPermissions.Contains(permission, StringComparer.OrdinalIgnoreCase))
            {
                session.Permissions.GrantedPermissions.Add(permission);
            }

            // Remove from denied if present
            session.Permissions.DeniedPermissions.RemoveAll(
                p => string.Equals(p, permission, StringComparison.OrdinalIgnoreCase));

            SaveSession(session);
        }

        public void DenyPermission(UserSession session, string permission)
        {
            if (session == null) throw new ArgumentNullException(nameof(session));
            if (string.IsNullOrWhiteSpace(permission)) throw new ArgumentException("Permission required.", nameof(permission));

            if (!session.Permissions.DeniedPermissions.Contains(permission, StringComparer.OrdinalIgnoreCase))
            {
                session.Permissions.DeniedPermissions.Add(permission);
            }

            SaveSession(session);
        }

        public bool CheckPermission(UserSession session, string permission)
        {
            if (session == null) return false;
            return PermissionEvaluator.HasPermission(session.Permissions, permission);
        }

        private string GetSessionFilePath(string sessionId)
        {
            // Use only the filename portion to prevent directory traversal
            string safeFileName = Path.GetFileName(sessionId + ".json");
            string fullPath = Path.GetFullPath(Path.Combine(_sessionDirectory, safeFileName));

            // Verify the resolved path is within the session directory
            string resolvedDirectory = Path.GetFullPath(_sessionDirectory);
            if (!fullPath.StartsWith(resolvedDirectory, StringComparison.OrdinalIgnoreCase))
            {
                throw new InvalidOperationException("Attempted path traversal detected.");
            }

            return fullPath;
        }

        private static string GenerateSecureSessionId()
        {
            // Use cryptographic random bytes for session ID
            byte[] bytes = new byte[32];
            using (var rng = System.Security.Cryptography.RandomNumberGenerator.Create())
            {
                rng.GetBytes(bytes);
            }
            return Convert.ToHexString(bytes).ToLowerInvariant();
        }

        private static bool IsValidSessionId(string sessionId)
        {
            if (string.IsNullOrWhiteSpace(sessionId) || sessionId.Length > 128)
                return false;

            foreach (char c in sessionId)
            {
                if (!char.IsLetterOrDigit(c) && c != '-' && c != '_')
                    return false;
            }

            return true;
        }

        public void Dispose()
        {
            if (!_disposed)
            {
                _disposed = true;
            }
        }
    }

