            // Update preferences
            session.Preferences.Theme = "dark";
            session.Preferences.Language = "en";
            session.Preferences.ItemsPerPage = 50;
            manager.SaveSession(session);
            Console.WriteLine("Updated preferences (theme=dark, lang=en, itemsPerPage=50)");

            // Add items to cart
