            // Grant permissions
            manager.GrantPermission(session, "read");
            manager.GrantPermission(session, "write");
            manager.GrantPermission(session, "view_reports");
            session.Permissions.Role = "user";
            manager.SaveSession(session);
            Console.WriteLine("Granted permissions: read, write, view_reports (role=user)");

            // Check permissions
            Console.WriteLine($"  Has 'read': {manager.CheckPermission(session, "read")}");
            Console.WriteLine($"  Has 'delete': {manager.CheckPermission(session, "delete")}");
            Console.WriteLine($"  Has 'admin': {manager.CheckPermission(session, "admin")}");
            Console.WriteLine();

            // Deny a permission
            manager.DenyPermission(session, "write");
            Console.WriteLine("Denied 'write' permission.");
            Console.WriteLine($"  Has 'write': {manager.CheckPermission(session, "write")}");
            Console.WriteLine();

            // Reload session from disk to prove persistence
            var reloaded = manager.LoadSession(session.SessionId);
            if (reloaded != null)
            {
                Console.WriteLine("Reloaded session from disk:");
                Console.WriteLine($"  User: {reloaded.UserId}");
                Console.WriteLine($"  Theme: {reloaded.Preferences.Theme}");
                Console.WriteLine($"  Cart items: {reloaded.Cart.Items.Count}");
                Console.WriteLine($"  Cart total: ${reloaded.Cart.CartTotal:F2}");
                Console.WriteLine($"  Granted permissions: {string.Join(", ", reloaded.Permissions.GrantedPermissions)}");
                Console.WriteLine($"  Denied permissions: {string.Join(", ", reloaded.Permissions.DeniedPermissions)}");
                Console.WriteLine($"  Role: {reloaded.Permissions.Role}");
            }
            Console.WriteLine();

            // Demonstrate validation catches bad data
            Console.WriteLine("=== Validation Demo ===");
            var badSession = new UserSession
            {
                SessionId = "valid-id",
                UserId = "user-999",
                CreatedAt = DateTime.UtcNow,
                LastAccessedAt = DateTime.UtcNow,
                ExpiresAt = DateTime.UtcNow.AddHours(1),
                Preferences = new UserPreferences { Theme = "malicious_theme", Language = "xx" },
                Cart = new ShoppingCart(),
                Permissions = new UserPermissions { Role = "superuser_hacker" }
            };

            var (isValid, errors) = SessionValidator.Validate(badSession);
            Console.WriteLine($"Bad session valid: {isValid}");
            foreach (var error in errors)
            {
                Console.WriteLine($"  Error: {error}");
            }
            Console.WriteLine();

            // Remove cart item
            manager.RemoveFromCart(reloaded ?? session, "PROD-002");
            Console.WriteLine("Removed PROD-002 from cart.");
            var updated = manager.LoadSession(session.SessionId);
            if (updated != null)
            {
                Console.WriteLine($"  Cart now has {updated.Cart.Items.Count} items, total: ${updated.Cart.CartTotal:F2}");
            }

            // Clean up
            manager.DeleteSession(session.SessionId);
            Console.WriteLine();
            Console.WriteLine("Session deleted. Demo complete.");

            // Clean up demo directory
            try { Directory.Delete(sessionDir, true); } catch { }
        }
